"use strict";parserFactory.register("kaystls.site",()=>new KaystlsParser);class KaystlsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.wp-block-columns a.wp-block-navigation-item__content")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.wp-block-columns")}extractTitleImpl(e){return e.querySelector("div.wp-block-columns.alignwide h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"div.code-block, #nav_inner_page_backwards, #nav_inner_page_forwards, #message_content, .donate"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.wp-block-cover")}}